 const raw = String(
  $input.first().json.output
 ).trim();

 // 2. Проверяем формат tavily(query="...")
 const regex = /^tavily\(query="(.+)"\)$/;
 const match = raw.match(regex);

 const isTavily = !!match;
 const query = match ? match[1] : null;

 // 3. Добавляем служебные поля в item
 item.json.llmRaw = raw;       // исходный ответ LLM
 item.json.isTavily = isTavily; // true/false — это запрос к интернету?
 item.json.tavilyQuery = query; // сам текст внутри query="..."

 return item;
});

