// @ts-nocheck

function extractJsonString(text) {
  if (typeof text !== 'string') return null;

  let t = text.trim();

  // Strip code fences if present
  if (t.startsWith('```')) {
    t = t.replace(/^```[a-zA-Z]*\s*/, '');
    t = t.replace(/```$/, '').trim();
  }

  // Whole string is JSON
  try {
    JSON.parse(t);
    return t;
  } catch (e) {}

  // Try extract first {...} block
  const first = t.indexOf('{');
  const last = t.lastIndexOf('}');
  if (first !== -1 && last !== -1 && last > first) {
    const candidate = t.slice(first, last + 1);
    try {
      JSON.parse(candidate);
      return candidate;
    } catch (e) {}
  }

  return null;
}

function normalizePlanObject(obj) {
  if (!obj || typeof obj !== 'object') throw new Error('Plan must be an object');

  const requiredTop = ['plan_title', 'plan'];
  for (const k of requiredTop) {
    if (!(k in obj)) throw new Error('Plan JSON missing top-level field: ' + k);
  }

  const planTitle = String(obj.plan_title ?? '').trim();
  if (!planTitle) throw new Error('plan_title must be a non-empty string');

  if (!Array.isArray(obj.plan)) throw new Error('plan must be an array');

  // 3..6 items only
  if (obj.plan.length < 3 || obj.plan.length > 6) {
    throw new Error('plan must contain from 3 to 6 items');
  }

  const plan = obj.plan.map((it, i) => {
    const item = (it && typeof it === 'object') ? it : {};
    const expectedId = 'p' + (i + 1);

    const title = String(item.title ?? '').trim();
    if (!title) throw new Error(`plan[${i}] title must be a non-empty string`);

    return { id: expectedId, title };
  });

  return { plan_title: planTitle, plan };
}

// --- Main ---

// Берём userId из Telegram Trigger (надёжно)
const userId = String($('Telegram Trigger').first().json?.message?.chat?.id);
if (!userId) throw new Error('Could not resolve userId from Telegram message');

const raw = String($input.first()?.json?.output ?? $input.first()?.json?.text ?? $json.output ?? $json.text ?? '');
const jsonStr = extractJsonString(raw);
if (!jsonStr) throw new Error('Could not find valid plan JSON in output/text');

let planObj;

// 🔥 ОБРАБОТКА ЭКРАНИРОВАННОГО JSON
try {
  planObj = JSON.parse(jsonStr);
} catch (e) {
  try {
    if (jsonStr.startsWith('"') && jsonStr.endsWith('"')) {
      const unescaped = jsonStr.slice(1, -1)
        .replace(/\\"/g, '"')
        .replace(/\\n/g, '\n')
        .replace(/\\r/g, '\r')
        .replace(/\\t/g, '\t');
      planObj = JSON.parse(unescaped);
    } else {
      throw new Error('Cannot unescape: not wrapped in quotes');
    }
  } catch (e2) {
    throw new Error('Failed to parse JSON after unescaping: ' + e2.message);
  }
}

planObj = normalizePlanObject(planObj);

// Save to workflow static data
const sd = $getWorkflowStaticData('global');
sd.learning ??= { users: {} };

// ✅ ПОЛНАЯ ОЧИСТКА СТАРОГО СОСТОЯНИЯ
delete sd.learning.users[userId];

// ✅ СОЗДАНИЕ НОВОГО ПЛАНА
sd.learning.users[userId] = {
  profile: {},
  plan: planObj.plan,
  plan_title: planObj.plan_title,
  currentIndex: 0,
  sentByPlanItem: {}
};

return [{
  json: {
    userId,
    saved: true,
    hasPlan: true,
    plan_title: planObj.plan_title,
    planSize: planObj.plan.length,
    plan: planObj.plan,
  }
}];

// @ts-nocheck

const input = $input.first()?.json ?? {};

const userId = String(input.userId ?? '');
if (!userId) throw new Error('Could not resolve userId from $input.first().json.userId');

const planTitle = String(input.plan_title ?? '').trim();

const plan = Array.isArray(input.plan) ? input.plan : [];

let text = '';

if (plan.length > 0) {
  const lines = [];
  lines.push('Ваш план обучения:');
  if (planTitle) lines.push(planTitle);
  lines.push('');

  for (let i = 0; i < plan.length; i++) {
    const p = plan[i] ?? {};
    const title = String(p.title ?? '(без названия)');
    lines.push(String(i + 1) + ') ' + title);
  }

  text = lines.join('\n').trim();

  const MAX = 3500;
  if (text.length > MAX) {
    text = text.slice(0, MAX - 20).trim() + '\n\n(сообщение сокращено)';
  }
} else {
  text = 'План обучения пока не найден. Напишите цель обучения, и я составлю план.';
}

return [{ json: { userId, text } }];

// @ts-nocheck
// NODE B (Format/Pass-through): делает “всё остальное” (формирование структуры под агента/следующие ноды).
// По сути — безопасно нормализует и отдаёт ровно то, что нужно дальше.

const input = $('If1').first()?.json ?? {};

const userId = $('Telegram Trigger').first().json.message.chat.id
if (!userId) throw new Error('userId is required');

const hasPlan = Boolean(input.hasPlan);
const done = Boolean(input.done);

if (!hasPlan) {
  // Пробрасываем как есть (ветка: плана нет или план завершён и очищен)
  return [{
    json: {
      userId,
      hasPlan,
      done,
      needPlan: Boolean(input.needPlan),
      message: String(input.message ?? '')
    }
  }];
}

// План есть, тема подготовлена в Node A
const planTitle = String(input.plan_title ?? '').trim();
const planSize = Number(input.planSize ?? 0);

const topic = input.topic ?? {};
const topicId = String(topic.id ?? '');
const topicTitle = String(topic.title ?? '').trim();
const topicIndex = Number(topic.index ?? 0);
const topicTotal = Number(topic.total ?? 0);

return [{
  json: {
    userId,
    hasPlan: true,
    done: false,
    plan_title: planTitle,
    planSize,
    topic: {
      id: topicId,
      title: topicTitle,
      index: topicIndex,
      total: topicTotal
    }
  }
}];

// @ts-nocheck
const userId = String($('Telegram Trigger').first().json?.message?.chat?.id ?? '');
if (!userId) throw new Error('userId not found');

const sd = $getWorkflowStaticData('global');
sd.learning ??= { users: {} };
sd.learning.users ??= {};

if (sd.learning.users[userId]) {
  delete sd.learning.users[userId];
}

return [{ json: { ok: true, action: 'deleted user', userId } }];

// @ts-nocheck
// NODE A (State): двигает указатель вперёд и чистит static data, если план закончился.
// Вход: userId (можно брать из Telegram Trigger, как у вас)

const userId = String($('Telegram Trigger').first().json?.message?.chat?.id ?? '');
if (!userId) throw new Error('userId is required');

const sd = $getWorkflowStaticData('global');
sd.learning ??= { users: {} };
sd.learning.users ??= {};

const user = sd.learning.users[userId];

// Если пользователя/плана нет — отдаём флаги и выходим
if (!user || !Array.isArray(user.plan) || user.plan.length === 0) {
  return [{
    json: {
      userId,
      hasPlan: false,
      needPlan: true,
      done: false,
      message: 'Plan not found in static data'
    }
  }];
}

const planTitle = String(user.plan_title ?? '').trim();
const plan = user.plan;

let idx = Number.isFinite(user.currentIndex) ? user.currentIndex : 0;

// Если уже за концом — чистим и выходим
if (idx >= plan.length) {
  user.plan = [];
  user.plan_title = '';
  user.currentIndex = 0;
  user.sentByPlanItem = {};

  return [{
    json: {
      userId,
      hasPlan: false,
      done: true,
      message: 'Plan is finished'
    }
  }];
}

// Берём текущий пункт (до инкремента)
const item = plan[idx] ?? {};
const topicId = String(item.id ?? `p${idx + 1}`);
const topicTitle = String(item.title ?? '').trim() || '(без названия)';

// Двигаем указатель вперёд
user.currentIndex = idx + 1;

return [{
  json: {
    userId,
    hasPlan: true,
    done: false,
    plan_title: planTitle,
    planSize: plan.length,
    // ВАЖНО: отдаём тему, чтобы следующая нода не лазила в static data
    topic: {
      id: topicId,
      title: topicTitle,
      index: idx + 1,
      total: plan.length
    }
  }
}];

// @ts-nocheck
const userId = $input.first().json.userId;
const sd = $getWorkflowStaticData('global');
if (sd.learning?.users?.[userId]) {
  delete sd.learning.users[userId];
}
return [{ json: { userId, text: "Тема изучена, поздравляю! Хотите изучить что-то ещё?" } }];
